'use client';

import type { CreativeRequest, RequestStatus } from '@/types';
import { REQUEST_STATUS_LABELS } from '@/types';
import { RequestCard } from './request-card';

interface KanbanColumnProps {
  status: RequestStatus;
  requests: CreativeRequest[];
  onCardClick: (request: CreativeRequest) => void;
}

const STATUS_COLORS: Record<RequestStatus, string> = {
  open: 'bg-blue-50 border-blue-200',
  in_progress: 'bg-amber-50 border-amber-200',
  review: 'bg-violet-50 border-violet-200',
  closed: 'bg-emerald-50 border-emerald-200',
};

const STATUS_DOT: Record<RequestStatus, string> = {
  open: 'bg-blue-500',
  in_progress: 'bg-amber-500',
  review: 'bg-violet-500',
  closed: 'bg-emerald-500',
};

export const KanbanColumn = ({ status, requests, onCardClick }: KanbanColumnProps) => {
  return (
    <div className="flex min-w-[280px] max-w-[320px] flex-1 flex-col">
      {/* Column Header */}
      <div className="mb-3 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className={`h-2 w-2 rounded-full ${STATUS_DOT[status]}`} />
          <h3 className="text-sm font-semibold text-[var(--text-primary)]">
            {REQUEST_STATUS_LABELS[status]}
          </h3>
        </div>
        <span className="flex h-5 min-w-[20px] items-center justify-center rounded-full bg-[var(--surface-secondary)] px-1.5 text-xs font-medium text-[var(--text-secondary)]">
          {requests.length}
        </span>
      </div>

      {/* Column Body */}
      <div
        className={`
          flex flex-1 flex-col gap-2 rounded-[var(--radius-lg)] border p-2
          ${STATUS_COLORS[status]}
          overflow-y-auto
        `}
        style={{ maxHeight: 'calc(100vh - 200px)' }}
      >
        {requests.length === 0 ? (
          <div className="flex flex-1 items-center justify-center py-12">
            <span className="text-sm text-[var(--text-tertiary)]">No requests</span>
          </div>
        ) : (
          requests.map((request) => (
            <RequestCard key={request.id} request={request} onClick={onCardClick} />
          ))
        )}
      </div>
    </div>
  );
};
